WITH payload AS (
  SELECT $RISQQ121${"questions":[{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.3","internal_question_no":"10A.003","question_sort_key":10100300.417,"question_text":"Are the certificates of mooring lines and mooring tails available on board?","guide_to_inspection":"A mill certificate or certificate of conformity issued by the rope manufacturer does not necessarily guarantee the quality of the mooring\nline or the proper execution of quality control. RightShip recommends that mooring lines should be accompanied by a type approval\ncertificate issued by one of the IACS members. This type approval certificate not only assesses the product’s performance but also\nincludes requirements for quality control and production processes, thereby providing the most reliable evidence of consistent\nperformance and quality over time. Mooring lines that do not possess type approval certificates could still comply with Q10.3 by\nproviding a verification statement. This statement should confirm that a surveyor from a classification society, or a third party approved\nby the classification society, has witnessed the product test in accordance with specific standards listed in the statement. This\nverification statement should pertain to a specific batch, and the rope in use should originate from that batch.\nIt is important that all ropes and wires used for mooring have a certificate. It is considered good practice for these certificates to be\nclearly labelled and kept in an easily accessible file. A method of correct identification and matching of individual certificates with the\nmooring ropes and wires should be established on board. Mooring ropes, mooring pendants and wires without certificates must not be\nused on board.\nAn example of a mooring line base design certificate, mooring tail base design certificate, mooring line certificate and\nmooring tail certificate as developed by OCIMF and the template documents can be found on the website here.\nThe mooring line and mooring tail data sheet shall be provided by the line manufacturer. The recommended contents of data sheet can\nbe found in B4 of appendix B of MEG4.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":184,"source_page_end":184,"raw_source_text":"Are the certificates of mooring lines and mooring tails available on board? (V & M)\nGuide to Inspection\nA mill certificate or certificate of conformity issued by the rope manufacturer does not necessarily guarantee the quality of the mooring\nline or the proper execution of quality control. RightShip recommends that mooring lines should be accompanied by a type approval\ncertificate issued by one of the IACS members. This type approval certificate not only assesses the product’s performance but also\nincludes requirements for quality control and production processes, thereby providing the most reliable evidence of consistent\nperformance and quality over time. Mooring lines that do not possess type approval certificates could still comply with Q10.3 by\nproviding a verification statement. This statement should confirm that a surveyor from a classification society, or a third party approved\nby the classification society, has witnessed the product test in accordance with specific standards listed in the statement. This\nverification statement should pertain to a specific batch, and the rope in use should originate from that batch.\nIt is important that all ropes and wires used for mooring have a certificate. It is considered good practice for these certificates to be\nclearly labelled and kept in an easily accessible file. A method of correct identification and matching of individual certificates with the\nmooring ropes and wires should be established on board. Mooring ropes, mooring pendants and wires without certificates must not be\nused on board.\nAn example of a mooring line base design certificate, mooring tail base design certificate, mooring line certificate and\nmooring tail certificate as developed by OCIMF and the template documents can be found on the website here.\nThe mooring line and mooring tail data sheet shall be provided by the line manufacturer. The recommended contents of data sheet can\nbe found in B4 of appendix B of MEG4.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.4","internal_question_no":"10A.004","question_sort_key":10100400.418,"question_text":"Do mooring lines and mooring tails comply with industry guidelines and are they in good order?","guide_to_inspection":"Any increase in the LDBF of the mooring lines above the specified limits, i.e., 100 to 105 percent of the Ship Design MBL, will require the\nclassification society to conduct a review of the mooring equipment and fittings’ operational characteristics and load limitations, as well\nas their hull supporting structures.\nRecord a comment if one or more mooring lines carried onboard, either in service or as spares, have a Line Design Break Force (LDBF)\ngreater than 105% of the ship’s design MBL. Specify the number of lines affected and the actual LDBF expressed as a percentage of the\nship’s design MBL.\nRecord a comment if one or more mooring tails carried onboard, either in service or as spares. have a Tail Design Break Force (TDBF)\ngreater than 130% of the ship’s design MBL. Specify the number of tails affected and the actual TDBF expressed as a percentage of the\nship’s design MBL.\nRecord a Finding if any mooring lines onboard, mounted on a winch, loose, or carried as spares, have an LDBF lower than 100% of the\nship’s design MBL.\nRecord a Finding if any mooring tails onboard, either in service or carried as spares, have a TDBF lower than 125% of the ship’s design\nMBL.\nRecord a Finding if the vessel was equipped with HMPE mooring lines but without mooring tails fitted.\nThe Line Design Break Force (LDBF) of mooring lines fitted on board shall be 100-105% of the ship design MBL. The ship designed\nminimum breaking strength of each mooring line is available in the mooring arrangement plan.\nNylon (polyamide) mooring lines and tails should be specified as break tested wet, because nylon lines and tails change strength\ncharacteristics once exposed to water and generally do not fully dry to their original construction state.\nMooring tails experience more wear in services than lines, and for this reason the Tail Design Break Force (TDBF) should be higher than\nthe LDBF. The TDBF of tails should be 125% - 130% of the ship’s design MBL. The increase in TDBF will not necessarily increase tail\nfatigue life and may undermine the integrity of the mooring system by reducing system compliance.\nThe standard recommended overall length for mooring tails is 11 metres, however for exposed mooring a 22-metre tail provides\nadditional elongation in the mooring arrangement. Mooring tails should be inspected before every use and according to the requirements\nof the LMP.\nThe vessel’s manager should arrange for the retirement of the mooring lines and tails when their residual strength reaches 75% of the\nship’s design MBL.\nTails can be attached directly to HMSF mooring lines using a cow hitch. A cow hitch is a method of joining two fibre ropes without\nusing connection devices. Worked cow hitch connection can be become very tight and the inclusion of a pigtail is recommended to help\nseparate the tail and mooring line for replacement or inspection.\n(Mooring Equipment Guidelines (MEG4), 2018)\nThe mooring ropes should be stowed clear of the deck, preferably on a pallet. The area should also be free of any obstructions which\ncould hinder the view of the mooring deck. The mooring stations so far as possible should be painted with a non-slip treatment.\n(Safe Mooring Practice, 2009)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":184,"source_page_end":184,"raw_source_text":"Do mooring lines and mooring tails comply with industry guidelines and are they in good order? (V & M)\nGuide to Inspection\nAny increase in the LDBF of the mooring lines above the specified limits, i.e., 100 to 105 percent of the Ship Design MBL, will require the\nclassification society to conduct a review of the mooring equipment and fittings’ operational characteristics and load limitations, as well\nas their hull supporting structures.\nRecord a comment if one or more mooring lines carried onboard, either in service or as spares, have a Line Design Break Force (LDBF)\ngreater than 105% of the ship’s design MBL. Specify the number of lines affected and the actual LDBF expressed as a percentage of the\nship’s design MBL.\nRecord a comment if one or more mooring tails carried onboard, either in service or as spares. have a Tail Design Break Force (TDBF)\ngreater than 130% of the ship’s design MBL. Specify the number of tails affected and the actual TDBF expressed as a percentage of the\nship’s design MBL.\nRecord a Finding if any mooring lines onboard, mounted on a winch, loose, or carried as spares, have an LDBF lower than 100% of the\nship’s design MBL.\nRecord a Finding if any mooring tails onboard, either in service or carried as spares, have a TDBF lower than 125% of the ship’s design\nMBL.\nRecord a Finding if the vessel was equipped with HMPE mooring lines but without mooring tails fitted.\nThe Line Design Break Force (LDBF) of mooring lines fitted on board shall be 100-105% of the ship design MBL. The ship designed\nminimum breaking strength of each mooring line is available in the mooring arrangement plan.\nNylon (polyamide) mooring lines and tails should be specified as break tested wet, because nylon lines and tails change strength\ncharacteristics once exposed to water and generally do not fully dry to their original construction state.\nMooring tails experience more wear in services than lines, and for this reason the Tail Design Break Force (TDBF) should be higher than\nthe LDBF. The TDBF of tails should be 125% - 130% of the ship’s design MBL. The increase in TDBF will not necessarily increase tail\nfatigue life and may undermine the integrity of the mooring system by reducing system compliance.\nThe standard recommended overall length for mooring tails is 11 metres, however for exposed mooring a 22-metre tail provides\nadditional elongation in the mooring arrangement. Mooring tails should be inspected before every use and according to the requirements\nof the LMP.\nThe vessel’s manager should arrange for the retirement of the mooring lines and tails when their residual strength reaches 75% of the\nship’s design MBL.\nTails can be attached directly to HMSF mooring lines using a cow hitch. A cow hitch is a method of joining two fibre ropes without\nusing connection devices. Worked cow hitch connection can be become very tight and the inclusion of a pigtail is recommended to help\nseparate the tail and mooring line for replacement or inspection.\n(Mooring Equipment Guidelines (MEG4), 2018)\nThe mooring ropes should be stowed clear of the deck, preferably on a pallet. The area should also be free of any obstructions which\ncould hinder the view of the mooring deck. The mooring stations so far as possible should be painted with a non-slip treatment.\n(Safe Mooring Practice, 2009)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.5","internal_question_no":"10A.005","question_sort_key":10100500.419,"question_text":"Is there a procedure for testing the winch brake rendering setting and is it being tested regularly?","guide_to_inspection":"Rightship recommends the vessel’s manager to set the brake at 60% of the Ship Design MBL as per OCIMF guidelines in section\n6.4.6 of the MEG 4. RightShip recommends that tests are conducted at least annually.\nEach winch manufacturer will have their own test equipment and procedure, which should be followed by the operator. Details of\nthe equipment and procedures should be in the instruction manual for the mooring winch.\nThe winch test procedure should include:\n> Preparing the winch for testing\n> Setting up the test gear and applying the test load\n> A curve or table relating hydraulic jack test pressure to line pull\n> Hydraulic Jack pressure at which the brake is designed to render\n> Setting of the winch brakes including the values for torque wrench or pressure gauge fitted for setting up the brakes\n> Recording the test results and ensuring markings on the drum are correct and visible\nFor an undivided winch drum, OCIMF recommended asking the manufacturer for guidance on maintaining the OCIMF\nrecommendations for brake rendering. This may require ship operational experience to identify the normal layer in use for most\nmooring operations.\nThe winch will need to be marked with a marking device after the test is done and the brake setting calibrated to ensure that the\nbrake is applied to the same torque during every mooring operation.\nThe marking device should be built so that further tightening in emergency conditions is not hampered, and it should be of suitable\nconstruction to remain in place and in good working condition between routine tests. The RightShip Lessons Learned and Best\nPractice circular “What is Mooring Winch Brake Render Testing” includes examples of both unsuitable and acceptable marker\ndesigns.\nThe main purpose of brake testing is to verify that the brake will render at a lower load than the Ship Design MBL. For conventional\nscrew brakes, a tag should be attached stating the torque value. For spring applied brakes the spring compression distance should\nbe recorded, and the mechanisms secured with a seal. A stopper arrangement, i.e. locking nut on the threaded end, should not be\nused on the tightening screw. Stopper arrangement can impede the brake setting and reduce the brake holding load. (Mooring\nEquipment Guidelines (MEG4), 2018)\nThe stall load or stall heaving capacity of a winch is the maximum short term or instantaneous pull of the winch, and the stall\nsetting is used to set the maximum heave power of the winch hydraulic motor. The stalling hydraulic pressure is controlled by a\nproportional valve, however over a period of years this can drift and change the winch setting. The winch stalling load should never\nexceed 50% of ship design MBL.\nThe Rightship Lessons Learned and Best Practice circular “ What is Mooring Winch Brake Render Testing” must be taken in to\naccount when performing mooring winch brake rendering test.\nPlease CLICK HERE to download the document.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":185,"source_page_end":185,"raw_source_text":"Is there a procedure for testing the winch brake rendering setting and is it being tested regularly? (V & M)\nGuide to Inspection\nRightship recommends the vessel’s manager to set the brake at 60% of the Ship Design MBL as per OCIMF guidelines in section\n6.4.6 of the MEG 4. RightShip recommends that tests are conducted at least annually.\nEach winch manufacturer will have their own test equipment and procedure, which should be followed by the operator. Details of\nthe equipment and procedures should be in the instruction manual for the mooring winch.\nThe winch test procedure should include:\n> Preparing the winch for testing\n> Setting up the test gear and applying the test load\n> A curve or table relating hydraulic jack test pressure to line pull\n> Hydraulic Jack pressure at which the brake is designed to render\n> Setting of the winch brakes including the values for torque wrench or pressure gauge fitted for setting up the brakes\n> Recording the test results and ensuring markings on the drum are correct and visible\nFor an undivided winch drum, OCIMF recommended asking the manufacturer for guidance on maintaining the OCIMF\nrecommendations for brake rendering. This may require ship operational experience to identify the normal layer in use for most\nmooring operations.\nThe winch will need to be marked with a marking device after the test is done and the brake setting calibrated to ensure that the\nbrake is applied to the same torque during every mooring operation.\nThe marking device should be built so that further tightening in emergency conditions is not hampered, and it should be of suitable\nconstruction to remain in place and in good working condition between routine tests. The RightShip Lessons Learned and Best\nPractice circular “What is Mooring Winch Brake Render Testing” includes examples of both unsuitable and acceptable marker\ndesigns.\nThe main purpose of brake testing is to verify that the brake will render at a lower load than the Ship Design MBL. For conventional\nscrew brakes, a tag should be attached stating the torque value. For spring applied brakes the spring compression distance should\nbe recorded, and the mechanisms secured with a seal. A stopper arrangement, i.e. locking nut on the threaded end, should not be\nused on the tightening screw. Stopper arrangement can impede the brake setting and reduce the brake holding load. (Mooring\nEquipment Guidelines (MEG4), 2018)\nThe stall load or stall heaving capacity of a winch is the maximum short term or instantaneous pull of the winch, and the stall\nsetting is used to set the maximum heave power of the winch hydraulic motor. The stalling hydraulic pressure is controlled by a\nproportional valve, however over a period of years this can drift and change the winch setting. The winch stalling load should never\nexceed 50% of ship design MBL.\nThe Rightship Lessons Learned and Best Practice circular “ What is Mooring Winch Brake Render Testing” must be taken in to\naccount when performing mooring winch brake rendering test.\nPlease CLICK HERE to download the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.6","internal_question_no":"10A.006","question_sort_key":10100600.42,"question_text":"Are mooring lines correctly deployed and tended?","guide_to_inspection":"To minimise the occurrence of line failures and risks of injury or loss of life from a resulting snapback, lines of the same\nlead should be made of the same material/rope type. As an example, if a vessel runs four headlines, all four lines must be\nconstructed with the same material/rope type.\nLines should be led, so far as possible, without sharp changes of direction. Wires and synthetic fibre ropes need to be kept\nseparate and not allowed to cross or be led through the same lead.\n> Breast lines should be run, so far as practicable, from as far forward and aft and at right angles to the fore and aft line of the\nvessel\n> Spring lines should be run, so far as practicable, parallel to the fore and aft line of the vessel\n> Where synthetic fibre ropes and wires are available, the same type and size of lines should be used for the same service\n> The mooring operations must be properly planned. For large ships on tidal berths, mooring plans are developed and agreed\nprior to vessel arrival, and the roles and responsibilities of each crew and officers are explained.\n> The vertical angle of the mooring lines should be kept to a minimum. The flatter the mooring line angle, the more effective\nthe line will be in resisting horizontally- applied loads on the ship.\n> Mooring lines of the same size and material should be used for all leads. If this is not possible, all lines in the same service,\ni.e., breast lines, spring lines, etc. should be the same size and type.\n> The mooring tails should be the same material and size.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":185,"source_page_end":185,"raw_source_text":"Are mooring lines correctly deployed and tended? (V)\nGuide to Inspection\nTo minimise the occurrence of line failures and risks of injury or loss of life from a resulting snapback, lines of the same\nlead should be made of the same material/rope type. As an example, if a vessel runs four headlines, all four lines must be\nconstructed with the same material/rope type.\nLines should be led, so far as possible, without sharp changes of direction. Wires and synthetic fibre ropes need to be kept\nseparate and not allowed to cross or be led through the same lead.\n> Breast lines should be run, so far as practicable, from as far forward and aft and at right angles to the fore and aft line of the\nvessel\n> Spring lines should be run, so far as practicable, parallel to the fore and aft line of the vessel\n> Where synthetic fibre ropes and wires are available, the same type and size of lines should be used for the same service\n> The mooring operations must be properly planned. For large ships on tidal berths, mooring plans are developed and agreed\nprior to vessel arrival, and the roles and responsibilities of each crew and officers are explained.\n> The vertical angle of the mooring lines should be kept to a minimum. The flatter the mooring line angle, the more effective\nthe line will be in resisting horizontally- applied loads on the ship.\n> Mooring lines of the same size and material should be used for all leads. If this is not possible, all lines in the same service,\ni.e., breast lines, spring lines, etc. should be the same size and type.\n> The mooring tails should be the same material and size.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.7","internal_question_no":"10A.007","question_sort_key":10100700.421,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":186,"source_page_end":186,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.8","internal_question_no":"10A.008","question_sort_key":10100800.422,"question_text":"Are all mooring lines on winches correctly reeled on drums, and if made fast ashore, are winch brakes secured and winches out of gear?","guide_to_inspection":"The effectiveness of the brake is dependent upon the rope being correctly reeled onto the drum. The direction of reeling the\nmooring line on the drum in accordance with manufacturer’s instructions is important to ensure that the brake will hold or\nrender at the correct load.\nThe winch brake should be applied, and the winch motor should be out of gear after the mooring operation.\n(Mooring Winch Brake Holding Capacity, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":186,"source_page_end":186,"raw_source_text":"Are all mooring lines on winches correctly reeled on drums, and if made fast ashore, are winch\nbrakes secured and winches out of gear? (V)\nGuide to Inspection\nThe effectiveness of the brake is dependent upon the rope being correctly reeled onto the drum. The direction of reeling the\nmooring line on the drum in accordance with manufacturer’s instructions is important to ensure that the brake will hold or\nrender at the correct load.\nThe winch brake should be applied, and the winch motor should be out of gear after the mooring operation.\n(Mooring Winch Brake Holding Capacity, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.9","internal_question_no":"10A.009","question_sort_key":10100900.423,"question_text":"On split drum winches, have the split drums been set up correctly after the completion of mooring operation?","guide_to_inspection":"Split drum winches are designed so that the line under tension is on the first wrap on the drum, providing maximum holding\npower. Excessive turns should not be left on the working side of a split mooring winch (tension drum).\n(Safe Mooring Practice, 2009)\nGuidance on the minimum number of turns on the tension drum should be obtained from the line manufacturer and\ndocumented in the Line Management Plan.\nSplit-drum winches should not have more than one layer of mooring line on the tension section of the drum because it can\nreduce the brake holding capacity of the mooring winch.\n(Mooring Equipment Guidelines (MEG4), 2018)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":186,"source_page_end":186,"raw_source_text":"On split drum winches, have the split drums been set up correctly after the completion of\nmooring operation? (V)\nGuide to Inspection\nSplit drum winches are designed so that the line under tension is on the first wrap on the drum, providing maximum holding\npower. Excessive turns should not be left on the working side of a split mooring winch (tension drum).\n(Safe Mooring Practice, 2009)\nGuidance on the minimum number of turns on the tension drum should be obtained from the line manufacturer and\ndocumented in the Line Management Plan.\nSplit-drum winches should not have more than one layer of mooring line on the tension section of the drum because it can\nreduce the brake holding capacity of the mooring winch.\n(Mooring Equipment Guidelines (MEG4), 2018)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.10","internal_question_no":"10A.010","question_sort_key":10101000.424,"question_text":"If mooring tails are used, have they properly connected to the main mooring lines in accordance with industry guidance?","guide_to_inspection":"It is critical that the mooring tails are to be connected to the primary mooring line by cow hitch or by shackle or link as per\nmanufacturer’s instruction. The SWL of the joining shackle should always be equal to or greater than the Working Load Limit\n(WLL) of the lines in the mooring system, so that the SWL will never be exceeded within the working load range of the lines to\nwhich they are attached. Although WLL values for wires and synthetic lines are slightly different (55% and 50% of Ship Design\nMBL respectively) it is not intended that joining shackle manufacturers or ship operators attempt to match the SWL of the\nshackle to the WLL.\nThe eyes of mooring pendants(tails), and in the absence of mooring pendants(tails), the mooring lines should be covered with\nchafe protection.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":186,"source_page_end":186,"raw_source_text":"If mooring tails are used, have they properly connected to the main mooring lines in accordance\nwith industry guidance? (V & M)\nGuide to Inspection\nIt is critical that the mooring tails are to be connected to the primary mooring line by cow hitch or by shackle or link as per\nmanufacturer’s instruction. The SWL of the joining shackle should always be equal to or greater than the Working Load Limit\n(WLL) of the lines in the mooring system, so that the SWL will never be exceeded within the working load range of the lines to\nwhich they are attached. Although WLL values for wires and synthetic lines are slightly different (55% and 50% of Ship Design\nMBL respectively) it is not intended that joining shackle manufacturers or ship operators attempt to match the SWL of the\nshackle to the WLL.\nThe eyes of mooring pendants(tails), and in the absence of mooring pendants(tails), the mooring lines should be covered with\nchafe protection.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.11","internal_question_no":"10A.011","question_sort_key":10101100.425,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":186,"source_page_end":186,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.12","internal_question_no":"10A.012","question_sort_key":10101200.426,"question_text":"Have the heaving lines been constructed with either a monkey’s fist or a small, high-visibility soft pouch at one end, with a total weight not exceeding 0.5 kg?","guide_to_inspection":"The “monkey’s fist” should be made with rope only and must not contain added weighting material. Safe alternatives include a\nsmall high-visibility soft pouch, filled with fast-draining pea shingle or similar, with a weight of not more than 0.5 kg. Under no\ncircumstances is a line to be weighted by items such as shackles, bolts or nuts, or twist locks.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nThere may be alternative, for example throwing rings of soft material, however under no circumstances shall the weight exceed\n0.5 KG.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":186,"source_page_end":186,"raw_source_text":"Have the heaving lines been constructed with either a monkey’s fist or a small, high-visibility soft pouch at\none end, with a total weight not exceeding 0.5 kg? (V)\nGuide to Inspection\nThe “monkey’s fist” should be made with rope only and must not contain added weighting material. Safe alternatives include a\nsmall high-visibility soft pouch, filled with fast-draining pea shingle or similar, with a weight of not more than 0.5 kg. Under no\ncircumstances is a line to be weighted by items such as shackles, bolts or nuts, or twist locks.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nThere may be alternative, for example throwing rings of soft material, however under no circumstances shall the weight exceed\n0.5 KG.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.13","internal_question_no":"10A.013","question_sort_key":10101300.427,"question_text":"Are the mooring stations maintained in a safe working condition, and is the entire mooring deck area clearly marked with visible signage and appropriately identified as a hazardous zone?","guide_to_inspection":"The entire area of the mooring deck should be considered a potential snap-back zone. All crew working on a mooring deck\nshould be made aware of this with clearly visible signage.\nThe painting of snap-back zones on mooring decks should be avoided because they may give a false sense of security. In effect,\nthe whole mooring deck may be considered a danger zone.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nThe mooring station should be well lit, clean, and free from oil leaks and the deck suitably prepared to prevent slips or trips.\nMooring areas naturally contain many trip hazards, and all surfaces are painted the same colour, hiding trip hazards such as\nsave-alls, windlass platforms, forecastle access hatch and bitts.\nPhysical hazards such as bulkhead frames, mooring bits, pedestal fairleads and cleats, platforms, and hawse pipe covers are to\nbe highlighted.\n(Safe Mooring Practice, 2009)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":187,"source_page_end":187,"raw_source_text":"Are the mooring stations maintained in a safe working condition, and is the entire mooring deck area\nclearly marked with visible signage and appropriately identified as a hazardous zone? (V)\nGuide to Inspection\nThe entire area of the mooring deck should be considered a potential snap-back zone. All crew working on a mooring deck\nshould be made aware of this with clearly visible signage.\nThe painting of snap-back zones on mooring decks should be avoided because they may give a false sense of security. In effect,\nthe whole mooring deck may be considered a danger zone.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nThe mooring station should be well lit, clean, and free from oil leaks and the deck suitably prepared to prevent slips or trips.\nMooring areas naturally contain many trip hazards, and all surfaces are painted the same colour, hiding trip hazards such as\nsave-alls, windlass platforms, forecastle access hatch and bitts.\nPhysical hazards such as bulkhead frames, mooring bits, pedestal fairleads and cleats, platforms, and hawse pipe covers are to\nbe highlighted.\n(Safe Mooring Practice, 2009)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.14","internal_question_no":"10A.014","question_sort_key":10101400.428,"question_text":"Are appropriate stoppers in use and are the mooring ropes turned up to bitts correctly?","guide_to_inspection":"Given the variety of synthetic fibre lines available, it is crucial to use the appropriate type of stopper. Polyamide, polypropylene,\nand polyethylene mix lines lack the necessary stiffness to function effectively as stoppers. HMSF ropes are generally too\nslippery to be used as stoppers.\nIdeally, a stopper should be:\n> Made of polyester\n> Used in a double configuration\n> Flexible yet made of a stiff material\n> Approximately two metres in effective length from the securing point\n> Thinner than the mooring line\n> About half as strong as the mooring line\n(Effective Mooring 2019)\nWhen laying up the line onto the mooring bitts, the first two turns should be taken directly around the first post of the bitts before\nthe rope is laid up in a figure eight around the bitts. Once a rope is laid up on the bitts the stopper should be released from the\nrope.\nDrum ends are not designed to have mooring ropes secured to them for long periods of time. Ropes should never be left on\ndrum ends when not tensioned; they must always be laid up on the bitts.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":187,"source_page_end":187,"raw_source_text":"Are appropriate stoppers in use and are the mooring ropes turned up to bitts correctly? (V)\nGuide to Inspection\nGiven the variety of synthetic fibre lines available, it is crucial to use the appropriate type of stopper. Polyamide, polypropylene,\nand polyethylene mix lines lack the necessary stiffness to function effectively as stoppers. HMSF ropes are generally too\nslippery to be used as stoppers.\nIdeally, a stopper should be:\n> Made of polyester\n> Used in a double configuration\n> Flexible yet made of a stiff material\n> Approximately two metres in effective length from the securing point\n> Thinner than the mooring line\n> About half as strong as the mooring line\n(Effective Mooring 2019)\nWhen laying up the line onto the mooring bitts, the first two turns should be taken directly around the first post of the bitts before\nthe rope is laid up in a figure eight around the bitts. Once a rope is laid up on the bitts the stopper should be released from the\nrope.\nDrum ends are not designed to have mooring ropes secured to them for long periods of time. Ropes should never be left on\ndrum ends when not tensioned; they must always be laid up on the bitts.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.15","internal_question_no":"10A.015","question_sort_key":10101500.429,"question_text":"Are the controls, linkages, operating levers, brake drums, brake linings, and pins of the winches, as well as the working access arrangement to the winches, in good working order?","guide_to_inspection":"The brake drum should be free of corrosion, pitting and rust scale.\nThe grease nipples should be free of rust, salt, paint and grit.\nCheck the brake lining for significant wear. Brakes should be closely examined to ensure all linkages are working correctly, brake\nband material thickness is adequate, and the condition of the brake lining is satisfactory. Equipment manufacturer’s manuals\nwill provide details of the permitted minimum brake band thickness.\nClutches should operate smoothly and pins for securing the clutches should be attached to the clutch control levers ready for\nuse.\nWinch control levers must be marked with the direction of operation for both paying out and heaving in.\nDrum ends should be kept free from damage and rust.\nThe bed plates of winches should be regularly inspected for deterioration or damage.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":187,"source_page_end":187,"raw_source_text":"Are the controls, linkages, operating levers, brake drums, brake linings, and pins of the winches, as well\nas the working access arrangement to the winches, in good working order?\nGuide to Inspection\nThe brake drum should be free of corrosion, pitting and rust scale.\nThe grease nipples should be free of rust, salt, paint and grit.\nCheck the brake lining for significant wear. Brakes should be closely examined to ensure all linkages are working correctly, brake\nband material thickness is adequate, and the condition of the brake lining is satisfactory. Equipment manufacturer’s manuals\nwill provide details of the permitted minimum brake band thickness.\nClutches should operate smoothly and pins for securing the clutches should be attached to the clutch control levers ready for\nuse.\nWinch control levers must be marked with the direction of operation for both paying out and heaving in.\nDrum ends should be kept free from damage and rust.\nThe bed plates of winches should be regularly inspected for deterioration or damage.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.16","internal_question_no":"10A.016","question_sort_key":10101600.43,"question_text":"Are the pedestal fairleads, roller fairleads and other rollers free of grooving, well-greased and free to turn?","guide_to_inspection":"Regular visual inspections of all types of fairleads should be incorporated in the Plan Maintenance System. Excessive clearance\nbetween roller and pedestal table is an indication that the roller pin is worn, meaning it will have lost part of its original strength\nand may fly back when under tension.\nGrooving over part of the surface of the roller indicates that the roller is frozen and that the line/wire is always chafing against\nthe roller in the same area. Grooving or corrosion and scale accelerates damage to the mooring lines/wires. If the fairlead is\nsubsequently used for lines with a different diameter, the sharp edges of the groove will damage the line through abrasion and\nchafing.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":188,"source_page_end":188,"raw_source_text":"Are the pedestal fairleads, roller fairleads and other rollers free of grooving, well-greased and free to turn? (V)\nGuide to Inspection\nRegular visual inspections of all types of fairleads should be incorporated in the Plan Maintenance System. Excessive clearance\nbetween roller and pedestal table is an indication that the roller pin is worn, meaning it will have lost part of its original strength\nand may fly back when under tension.\nGrooving over part of the surface of the roller indicates that the roller is frozen and that the line/wire is always chafing against\nthe roller in the same area. Grooving or corrosion and scale accelerates damage to the mooring lines/wires. If the fairlead is\nsubsequently used for lines with a different diameter, the sharp edges of the groove will damage the line through abrasion and\nchafing.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.17","internal_question_no":"10A.017","question_sort_key":10101700.431,"question_text":"Are the fairleads, rollers, bitts, chocks and other items of mooring equipment clearly marked with the relevant SWL?","guide_to_inspection":"The SWL of each shipboard fitting should be marked (by weld bead or equivalent) on the deck fittings used for mooring. The\nSWL should be expressed in tonnes (letter ’t’) or in kilo newtons (letter ‘KN’).","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":188,"source_page_end":188,"raw_source_text":"Are the fairleads, rollers, bitts, chocks and other items of mooring equipment clearly marked\nwith the relevant SWL? (V)\nGuide to Inspection\nThe SWL of each shipboard fitting should be marked (by weld bead or equivalent) on the deck fittings used for mooring. The\nSWL should be expressed in tonnes (letter ’t’) or in kilo newtons (letter ‘KN’).","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.18","internal_question_no":"10A.018","question_sort_key":10101800.432,"question_text":"Are the windlasses, anchors, locking bars, and cables, as well as the working access arrangement, in good working order and are they maintained as part of the plan maintenance system?","guide_to_inspection":"The following should be incorporated in the plan maintenance system:\n> Inspection of the anchor, anchor shackle, enlarged links, swivel, joining shackles (Kenter / Baldt / Lugless), anchor D\nshackles, shackle pins, crown pin, joining shackles, flukes, and shanks for damage, wear down and missing items.\n> Inspection of the cable for damage, wear down and missing studs. IACS class societies require anchor cable replacement\nwhen wear down exceeds 12% diameter.\n> Inspection of cable markings, both permanent and painted.\n> Brake band thickness and condition of mating surface.\n> Maintenance of hoist motors in accordance with manufacturer’s recommendations.\n> Gypsy for wear down.\n> Ranging of cables for inspection at routine dry dockings in line with Class requirements.\n> Check wear down of guillotine bar, hinge and securing pin.\n> Inspection of devil’s claw – if the devil’s claw is damaged it should be replaced. Repair of devil’s claw is not an acceptable\npractice.\n> Renewal of wire lashings periodically when damaged / corroded.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":188,"source_page_end":188,"raw_source_text":"Are the windlasses, anchors, locking bars, and cables, as well as the working access arrangement, in\ngood working order and are they maintained as part of the plan maintenance system? (V)\nGuide to Inspection\nThe following should be incorporated in the plan maintenance system:\n> Inspection of the anchor, anchor shackle, enlarged links, swivel, joining shackles (Kenter / Baldt / Lugless), anchor D\nshackles, shackle pins, crown pin, joining shackles, flukes, and shanks for damage, wear down and missing items.\n> Inspection of the cable for damage, wear down and missing studs. IACS class societies require anchor cable replacement\nwhen wear down exceeds 12% diameter.\n> Inspection of cable markings, both permanent and painted.\n> Brake band thickness and condition of mating surface.\n> Maintenance of hoist motors in accordance with manufacturer’s recommendations.\n> Gypsy for wear down.\n> Ranging of cables for inspection at routine dry dockings in line with Class requirements.\n> Check wear down of guillotine bar, hinge and securing pin.\n> Inspection of devil’s claw – if the devil’s claw is damaged it should be replaced. Repair of devil’s claw is not an acceptable\npractice.\n> Renewal of wire lashings periodically when damaged / corroded.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.19","internal_question_no":"10A.019","question_sort_key":10101900.433,"question_text":"Have the anchors been tightly secured in the hawse pipe?","guide_to_inspection":"Whilst moored alongside and anchors are not in use, they should be properly secured by brake and guillotine. The anchors should\nbe housed in hawse pipes properly.\nTight securing of the anchor in the hawse pipe during voyage will avoid excessive vibrations and prevent possible detachment of\nD-shackle.\n(Anchor loss-technical and operational challenges and recommendations, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":188,"source_page_end":188,"raw_source_text":"Have the anchors been tightly secured in the hawse pipe? (V)\nGuide to Inspection\nWhilst moored alongside and anchors are not in use, they should be properly secured by brake and guillotine. The anchors should\nbe housed in hawse pipes properly.\nTight securing of the anchor in the hawse pipe during voyage will avoid excessive vibrations and prevent possible detachment of\nD-shackle.\n(Anchor loss-technical and operational challenges and recommendations, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.20","internal_question_no":"10A.020","question_sort_key":10102000.434,"question_text":"Are the chain locker doors firmly battened down and are the bitter end securing arrangements located outside the chain locker and accessible?","guide_to_inspection":"The bitter end should be inspected regularly; the tools for quick release should be available.\nThe fastening should be provided with a means suitable to permit, in case of emergency, an easy slipping of the chain cables\nto sea, operable from an accessible position outside the chain locker. A specially marked (red painted) sledge hammer should\nalways also be installed in an accessible position to allow the release of the cable in any emergency.\n(Anchoring, Mooring and Towing Equipment, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":189,"source_page_end":189,"raw_source_text":"Are the chain locker doors firmly battened down and are the bitter end securing arrangements\nlocated outside the chain locker and accessible? (V)\nGuide to Inspection\nThe bitter end should be inspected regularly; the tools for quick release should be available.\nThe fastening should be provided with a means suitable to permit, in case of emergency, an easy slipping of the chain cables\nto sea, operable from an accessible position outside the chain locker. A specially marked (red painted) sledge hammer should\nalways also be installed in an accessible position to allow the release of the cable in any emergency.\n(Anchoring, Mooring and Towing Equipment, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.21","internal_question_no":"10A.021","question_sort_key":10102100.435,"question_text":"Is the Master aware of the limitations of anchoring equipment?","guide_to_inspection":"Anchoring equipment is only to be used for the temporary mooring of a vessel, within a harbour or a sheltered area, when\nawaiting berth, tide, etc. It is particularly emphasised that the equipment is not designed to hold a ship off a fully exposed coast\nin bad weather or to stop a vessel from drifting.\nThe rules for anchoring equipment, including the grade, length and size of chain, the number and weight of the anchors, the\nstrength of the chain stoppers and the power of the anchor windlasses and the brakes are established by the class societies.\nThey can be found in the rules of the individual societies, or in the unified rules of IACS, the International Association of Class\nSocieties. It is important to be aware that these are minimum requirements, and to know the assumptions made in the\ncalculations.\nFor each vessel, the class society will calculate an equipment number by using a formula, which includes the displacement of\nthe vessel, the breadth of the ship and the height from the summer load waterline to the top of the uppermost house, as well as\nthe profile view area of the hull, superstructures, and houses above the summer load waterline.\nThus, the forces on the ship by current and wind from both the front and the sides are taken into account.\nThe formula is based on an assumption that the speed of the current may reach 2.5 m/sec, and wind speed of 25 m/sec (which\nrepresents quite high forces), but it is also assumed that the vessel can use a scope between 6 and 10 – the scope being the\nratio between lengths of chain paid out and water depth.\nHowever, large ships at deep anchorages do not have sufficient chain on board to reach scopes of such magnitude. If a ship is at\nanchor in ballast condition, the Master should also bear in mind that wind forces acting on the ship may be much larger than the\ncalculations have accounted for, as larger ship side areas are now exposed while the measurements entered in the formula were\ntaken from the summer load water line.\n(Limitations of a vessels’ anchoring equipment, 2010)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":189,"source_page_end":189,"raw_source_text":"Is the Master aware of the limitations of anchoring equipment? (V)\nGuide to Inspection\nAnchoring equipment is only to be used for the temporary mooring of a vessel, within a harbour or a sheltered area, when\nawaiting berth, tide, etc. It is particularly emphasised that the equipment is not designed to hold a ship off a fully exposed coast\nin bad weather or to stop a vessel from drifting.\nThe rules for anchoring equipment, including the grade, length and size of chain, the number and weight of the anchors, the\nstrength of the chain stoppers and the power of the anchor windlasses and the brakes are established by the class societies.\nThey can be found in the rules of the individual societies, or in the unified rules of IACS, the International Association of Class\nSocieties. It is important to be aware that these are minimum requirements, and to know the assumptions made in the\ncalculations.\nFor each vessel, the class society will calculate an equipment number by using a formula, which includes the displacement of\nthe vessel, the breadth of the ship and the height from the summer load waterline to the top of the uppermost house, as well as\nthe profile view area of the hull, superstructures, and houses above the summer load waterline.\nThus, the forces on the ship by current and wind from both the front and the sides are taken into account.\nThe formula is based on an assumption that the speed of the current may reach 2.5 m/sec, and wind speed of 25 m/sec (which\nrepresents quite high forces), but it is also assumed that the vessel can use a scope between 6 and 10 – the scope being the\nratio between lengths of chain paid out and water depth.\nHowever, large ships at deep anchorages do not have sufficient chain on board to reach scopes of such magnitude. If a ship is at\nanchor in ballast condition, the Master should also bear in mind that wind forces acting on the ship may be much larger than the\ncalculations have accounted for, as larger ship side areas are now exposed while the measurements entered in the formula were\ntaken from the summer load water line.\n(Limitations of a vessels’ anchoring equipment, 2010)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.22","internal_question_no":"10A.022","question_sort_key":10102200.436,"question_text":"Has the vessel been provided with a ship-specific Emergency Towing Booklet?","guide_to_inspection":"Applicable to cargo ships constructed on or after 1st January 2010; and cargo ships constructed before 1st January 2010, with\neffect from 1st January 2012.\n> The Emergency Towing Booklet (ETB) should be ship-specific and presented in a clear, concise, and ready-to-use format\n(booklet, plan, poster etc.).\n> A minimum of three copies should be kept on board and located in:\n1. The Bridge\n2. A forecastle space\n3. The ship’s office or cargo control room\nThe emergency towing procedure shall include:\n1. Drawings of fore and aft deck showing possible emergency towing arrangements\n2. An inventory of equipment on board that can be used for emergency towing\n3. Means and methods of communication\n4. Sample procedures to facilitate the preparation for and conduct of emergency towing operations.\n(SOLAS 74,2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":189,"source_page_end":189,"raw_source_text":"Has the vessel been provided with a ship-specific Emergency Towing Booklet? (V)\nGuide to Inspection\nApplicable to cargo ships constructed on or after 1st January 2010; and cargo ships constructed before 1st January 2010, with\neffect from 1st January 2012.\n> The Emergency Towing Booklet (ETB) should be ship-specific and presented in a clear, concise, and ready-to-use format\n(booklet, plan, poster etc.).\n> A minimum of three copies should be kept on board and located in:\n1. The Bridge\n2. A forecastle space\n3. The ship’s office or cargo control room\nThe emergency towing procedure shall include:\n1. Drawings of fore and aft deck showing possible emergency towing arrangements\n2. An inventory of equipment on board that can be used for emergency towing\n3. Means and methods of communication\n4. Sample procedures to facilitate the preparation for and conduct of emergency towing operations.\n(SOLAS 74,2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"10A","section_number":10,"section_letter":"A","section_title":"Mooring Operations","printed_question_no":"10.23","internal_question_no":"10A.023","question_sort_key":10102300.437,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":189,"source_page_end":189,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.1","internal_question_no":"11A.001","question_sort_key":11100100.438,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":190,"source_page_end":190,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.2","internal_question_no":"11A.002","question_sort_key":11100200.439,"question_text":"Is communication equipment, listed in the Record of Equipment attached to the Safety Radio Certificate or Safety Certificate (Form R or Form C), in good condition and has the GMDSS Logbook (the Radio Log) been maintained correctly and are daily, weekly and monthly tests being carried out?","guide_to_inspection":"The master must nominate one or more crew members, normally the person/s qualified for distress and safety radio\ncommunications, to maintain the radio log and to carry out the tests and checks of the equipment.\nDaily test:\n> The proper functioning of the Digital Selective Calling (DSC) facilities without radiation of signals, by the use of the\nequipment’s internal test facility.\n> Battery voltage checks. Mainly the battery ON LOAD and OFF LOAD voltages should be checked by a voltmeter connected\nto the charger.\n> Check that all printers are in a working condition.\nWeekly test:\n> Proper operation of the DSC facilities by means of a test call when within the communication range of a coast station fitted\nwith DSC equipment.\n> If batteries are not the reserve source of energy for the GMDSS equipment, the reserve source shall be tested.\nMonthly test:\n> The EPIRB should be examined by carrying out a self-test function without using the satellite system.\n> The Search and Rescue Transponder (SART) is equipped with a self-test mechanism to test the operational function of the\nbeacon. The SART to be tested using the ship’s X band radar.\n> Each survival craft should carry two-way VHF equipment to ensure proper operation in case of a distress situation. It\nshould be tested on a frequency other than vhf channel 16 (156.8 MHz). The expiry date of the battery needs to be checked\nand changed when required.\n> Battery: The battery connections and compartment should also be checked. The level of the electrolyte and the specific\ngravity of each cell should be checked and recorded.\n> All antennas for security of mounting and visible damage to the cables and insulators.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":190,"source_page_end":190,"raw_source_text":"Is communication equipment, listed in the Record of Equipment attached to the Safety Radio\nCertificate or Safety Certificate (Form R or Form C), in good condition and has the GMDSS Logbook\n(the Radio Log) been maintained correctly and are daily, weekly and monthly tests being carried out? (V)\nGuide to Inspection\nThe master must nominate one or more crew members, normally the person/s qualified for distress and safety radio\ncommunications, to maintain the radio log and to carry out the tests and checks of the equipment.\nDaily test:\n> The proper functioning of the Digital Selective Calling (DSC) facilities without radiation of signals, by the use of the\nequipment’s internal test facility.\n> Battery voltage checks. Mainly the battery ON LOAD and OFF LOAD voltages should be checked by a voltmeter connected\nto the charger.\n> Check that all printers are in a working condition.\nWeekly test:\n> Proper operation of the DSC facilities by means of a test call when within the communication range of a coast station fitted\nwith DSC equipment.\n> If batteries are not the reserve source of energy for the GMDSS equipment, the reserve source shall be tested.\nMonthly test:\n> The EPIRB should be examined by carrying out a self-test function without using the satellite system.\n> The Search and Rescue Transponder (SART) is equipped with a self-test mechanism to test the operational function of the\nbeacon. The SART to be tested using the ship’s X band radar.\n> Each survival craft should carry two-way VHF equipment to ensure proper operation in case of a distress situation. It\nshould be tested on a frequency other than vhf channel 16 (156.8 MHz). The expiry date of the battery needs to be checked\nand changed when required.\n> Battery: The battery connections and compartment should also be checked. The level of the electrolyte and the specific\ngravity of each cell should be checked and recorded.\n> All antennas for security of mounting and visible damage to the cables and insulators.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.3","internal_question_no":"11A.003","question_sort_key":11100300.44,"question_text":"Has the Satellite EPIRB been correctly installed, tested and maintained?","guide_to_inspection":"Satellite EPIRBs shall be tested at intervals not exceeding 12 months for all aspects of operational efficiency, with particular\nemphasis on frequency stability, signal strength and coding.\nSatellite EPIRBs are subject to shore-based maintenance at intervals not exceeding five years. (SOLAS 74,2020)\n406 MHz EPIRBs are to be physically examined and the self-test function checked at least once per month.\nCheck that the EPIRB ID and other information (include call sign and MMSI of the ship) is clearly marked on the body of the\nequipment.\nCheck for the presence of beacon operating instructions.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":190,"source_page_end":190,"raw_source_text":"Has the Satellite EPIRB been correctly installed, tested and maintained? (V & M)\nGuide to Inspection\nSatellite EPIRBs shall be tested at intervals not exceeding 12 months for all aspects of operational efficiency, with particular\nemphasis on frequency stability, signal strength and coding.\nSatellite EPIRBs are subject to shore-based maintenance at intervals not exceeding five years. (SOLAS 74,2020)\n406 MHz EPIRBs are to be physically examined and the self-test function checked at least once per month.\nCheck that the EPIRB ID and other information (include call sign and MMSI of the ship) is clearly marked on the body of the\nequipment.\nCheck for the presence of beacon operating instructions.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.4","internal_question_no":"11A.004","question_sort_key":11100400.441,"question_text":"Is the most current edition and up to date List of Radio Signals available on board?","guide_to_inspection":"The record of Equipment for Cargo Ship Safety (Form E) attached to the Cargo Ship Safety Equipment Certificate should be\nendorsed, if electronic nautical publications are provided.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":190,"source_page_end":190,"raw_source_text":"Is the most current edition and up to date List of Radio Signals available on board? (V)\nGuide to Inspection\nThe record of Equipment for Cargo Ship Safety (Form E) attached to the Cargo Ship Safety Equipment Certificate should be\nendorsed, if electronic nautical publications are provided.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.5","internal_question_no":"11A.005","question_sort_key":11100500.442,"question_text":"Is the vessel equipped with sufficient hand-held radios, for use in general on-board operations?","guide_to_inspection":"The primary means of communication between the personnel involved in shipboard operations and between the terminal and\nship are VHF or UHF radio.\nThe main difference between UHF and VHF radio is their range. UHF radio waves are smaller than VHF, which means that UHF\nfrequencies have smaller waves that produce a wider reception, while VHF has longer wavelengths. UHF signals are more likely\nto pass barriers like steel, bulkheads, and building walls more easily.\nVHF radio is generally a better signal for long-distance communication. UHF is particularly effective when using radios for\nindoor use, such as shipboard operations within the ship. An advantage of using UHF is that the crew is less likely to experience\ninterference from other two-way radios.\nSufficient portable radios with chargers and spare batteries should be available to allow communications between the Chief\nOfficer, deck officer in charge of cargo operations, the deck watch, and the Master.\nIf a vessel uses VHF radio for shipboard operations, the emergency channels and designated port operational channels must\nnot be used.\nThe GMDSS portable survival craft VHF units are designed for emergency use only. These radios are not for use in general on-\nboard operations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":191,"source_page_end":191,"raw_source_text":"Is the vessel equipped with sufficient hand-held radios, for use in general on-board operations? (V)\nGuide to Inspection\nThe primary means of communication between the personnel involved in shipboard operations and between the terminal and\nship are VHF or UHF radio.\nThe main difference between UHF and VHF radio is their range. UHF radio waves are smaller than VHF, which means that UHF\nfrequencies have smaller waves that produce a wider reception, while VHF has longer wavelengths. UHF signals are more likely\nto pass barriers like steel, bulkheads, and building walls more easily.\nVHF radio is generally a better signal for long-distance communication. UHF is particularly effective when using radios for\nindoor use, such as shipboard operations within the ship. An advantage of using UHF is that the crew is less likely to experience\ninterference from other two-way radios.\nSufficient portable radios with chargers and spare batteries should be available to allow communications between the Chief\nOfficer, deck officer in charge of cargo operations, the deck watch, and the Master.\nIf a vessel uses VHF radio for shipboard operations, the emergency channels and designated port operational channels must\nnot be used.\nThe GMDSS portable survival craft VHF units are designed for emergency use only. These radios are not for use in general on-\nboard operations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.6","internal_question_no":"11A.006","question_sort_key":11100600.443,"question_text":"Are Search and Rescue Radar Transponders (SARTs) in good order and tested regularly?","guide_to_inspection":"On vessels equipped with a minimum of two (2) search and rescue locating devices and free-fall lifeboats, one of the search and\nrescue locating devices should be stowed in a free-fall lifeboat. The other device should be situated in the immediate vicinity of the\nnavigation bridge, ensuring it can be utilized on board and is readily available for transfer to any other survival craft.\nThe Search and Rescue Radar Transponder as a part of GMDSS is subject to annual testing.\n(IMO Resolution A.802 (19).\nOne SART is required for ships of between 300 and 500 gross tons. Two SARTs are required for ships 500 gross tons or greater.\nEach SART should have self-test capability\n(Resolution A.802 (19) Performance Standards for Survival Craft Radar Transponders\nfor use in Search and Rescue Operations, 1995)\nCheck that the battery expiry label shows sufficient battery life to cover the next routine voyage.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":191,"source_page_end":191,"raw_source_text":"Are Search and Rescue Radar Transponders (SARTs) in good order and tested regularly? (V)\nGuide to Inspection\nOn vessels equipped with a minimum of two (2) search and rescue locating devices and free-fall lifeboats, one of the search and\nrescue locating devices should be stowed in a free-fall lifeboat. The other device should be situated in the immediate vicinity of the\nnavigation bridge, ensuring it can be utilized on board and is readily available for transfer to any other survival craft.\nThe Search and Rescue Radar Transponder as a part of GMDSS is subject to annual testing.\n(IMO Resolution A.802 (19).\nOne SART is required for ships of between 300 and 500 gross tons. Two SARTs are required for ships 500 gross tons or greater.\nEach SART should have self-test capability\n(Resolution A.802 (19) Performance Standards for Survival Craft Radar Transponders\nfor use in Search and Rescue Operations, 1995)\nCheck that the battery expiry label shows sufficient battery life to cover the next routine voyage.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.7","internal_question_no":"11A.007","question_sort_key":11100700.444,"question_text":"Are survival craft portable VHF radios in good order and charged?","guide_to_inspection":"Equipment for which the source of energy is intended to be user-replaceable should be provided with a dedicated primary\nbattery for use in the event of a distress situation. This battery should be equipped with a non-replaceable seal to indicate that it\nhas not been used.\n(Resolution A.809 (19) Performance Standards for Survival Craft Two-Way Radiotelephone Apparatus, 1995)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":191,"source_page_end":191,"raw_source_text":"Are survival craft portable VHF radios in good order and charged? (V)\nGuide to Inspection\nEquipment for which the source of energy is intended to be user-replaceable should be provided with a dedicated primary\nbattery for use in the event of a distress situation. This battery should be equipped with a non-replaceable seal to indicate that it\nhas not been used.\n(Resolution A.809 (19) Performance Standards for Survival Craft Two-Way Radiotelephone Apparatus, 1995)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.8","internal_question_no":"11A.008","question_sort_key":11100800.445,"question_text":"Is the AIS static, dynamic and voyage data up to date and has an AIS annual test been performed and the record available on board?","guide_to_inspection":"The Automatic Identification System (AIS) shall be subjected to an annual test by an approved surveyor or an approved testing\nor servicing facility. A copy of the test report shall be retained on board and should be in accordance with a model form set out in\nthe annex to MSC.1/Circ.1252.\n(SOLAS 74,2020) (MSC.1/Circ.1252, Guidelines on Annual\nTesting of the Automatic Identification System (AIS), 2007)\nStatic data that is set up during equipment installation and includes information such as MMSI, IMO Number, International call\nsign, beam, and ship type.\nDynamic data that is current navigation information including position, course, speed, and navigational status (at anchor,\nmoored, underway or special condition); and Voyage data relates to the specific voyage and include information on draft,\ndestination, ETA and hazardous cargo.\nIt is important that the AIS is operated correctly and that watch keepers are familiar with the equipment, including how to check that\nall information being transmitted by AIS is both accurate and update.\nBridge Procedures Guide, 2022)\nAccording to IMO guidelines provided by Resolution A.917(22), AIS should always be in operation when ships are underway or at\nanchor. Only if the Master believes that the continual operation of AIS might compromise the safety or security of the ship, the AIS\nmay be switched off.\nThe Master should report the switch-off and the reason for doing so to the competent authority. Actions of this nature should\nalways be recorded in the ship’s logbook together with the reason for doing so.\nRightship recommends that the date and time of switching on (and off as per above) should be recorded in the deck logbook.\nDeliberately turning off the transmitter signal without legitimate reason represents a breach of SOLAS and puts the ship in breach\nof flag state regulations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":192,"source_page_end":192,"raw_source_text":"Is the AIS static, dynamic and voyage data up to date and has an AIS annual test been performed\nand the record available on board? (V & M)\nGuide to Inspection\nThe Automatic Identification System (AIS) shall be subjected to an annual test by an approved surveyor or an approved testing\nor servicing facility. A copy of the test report shall be retained on board and should be in accordance with a model form set out in\nthe annex to MSC.1/Circ.1252.\n(SOLAS 74,2020) (MSC.1/Circ.1252, Guidelines on Annual\nTesting of the Automatic Identification System (AIS), 2007)\nStatic data that is set up during equipment installation and includes information such as MMSI, IMO Number, International call\nsign, beam, and ship type.\nDynamic data that is current navigation information including position, course, speed, and navigational status (at anchor,\nmoored, underway or special condition); and Voyage data relates to the specific voyage and include information on draft,\ndestination, ETA and hazardous cargo.\nIt is important that the AIS is operated correctly and that watch keepers are familiar with the equipment, including how to check that\nall information being transmitted by AIS is both accurate and update.\nBridge Procedures Guide, 2022)\nAccording to IMO guidelines provided by Resolution A.917(22), AIS should always be in operation when ships are underway or at\nanchor. Only if the Master believes that the continual operation of AIS might compromise the safety or security of the ship, the AIS\nmay be switched off.\nThe Master should report the switch-off and the reason for doing so to the competent authority. Actions of this nature should\nalways be recorded in the ship’s logbook together with the reason for doing so.\nRightship recommends that the date and time of switching on (and off as per above) should be recorded in the deck logbook.\nDeliberately turning off the transmitter signal without legitimate reason represents a breach of SOLAS and puts the ship in breach\nof flag state regulations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"11A","section_number":11,"section_letter":"A","section_title":"Radio and Communication","printed_question_no":"11.9","internal_question_no":"11A.009","question_sort_key":11100900.446,"question_text":"Is there a Shore-Based Maintenance Agreement in place to fulfil the maintenance requirements?","guide_to_inspection":"A shore-based maintenance agreement / certificate is needed on board to fulfil the maintenance requirements as mentioned\nin the “SOLAS GMDSS” regulations (CHAPTER IV Reg. 15) and the Radio Maintenance Guidelines (RES. A702-17), for GMDSS\nequipment sailing in Sea Area A2-A3-A4.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":192,"source_page_end":192,"raw_source_text":"Is there a Shore-Based Maintenance Agreement in place to fulfil the maintenance requirements? (M)\nGuide to Inspection\nA shore-based maintenance agreement / certificate is needed on board to fulfil the maintenance requirements as mentioned\nin the “SOLAS GMDSS” regulations (CHAPTER IV Reg. 15) and the Radio Maintenance Guidelines (RES. A702-17), for GMDSS\nequipment sailing in Sea Area A2-A3-A4.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.1","internal_question_no":"12A.001","question_sort_key":12100100.447,"question_text":"Is access to the ship being controlled by an adequate deck watch?","guide_to_inspection":"Even if it is not applicable under local regulations for some vessels to comply with the ISPS Code, it must be borne in mind that it is\ngood practice to have a member of the vessel’s crew permanently stationed at the gangway for safety purposes. They will be able\nto assist persons transiting the gangway as required and to monitor any dangerous practices. Gangway watch personnel must\nkeep in mind that they are the first point of contact on the vessel for anyone boarding.If a vessel is alongside a berth affected by\ntidal conditions, constant reassessment of the situation should be carried out. In addition, the watchman must have access to the\ntimes of high and low waters and be aware of any cargo operations which may affect the vessel’s trim. If a watchman is not present\nat the gangway and an incident occurs, the vessel’s crew may carry on with their duties unaware of the situation.\n(Gangways, 2014)\nThe deck watch has a responsibility to make all visitors aware of any specific hazards of the cargo or operations onboard the vessel\nand point out instructions to visitors what to do in the event of an emergency.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":193,"source_page_end":193,"raw_source_text":"Is access to the ship being controlled by an adequate deck watch? (V)\nGuide to Inspection\nEven if it is not applicable under local regulations for some vessels to comply with the ISPS Code, it must be borne in mind that it is\ngood practice to have a member of the vessel’s crew permanently stationed at the gangway for safety purposes. They will be able\nto assist persons transiting the gangway as required and to monitor any dangerous practices. Gangway watch personnel must\nkeep in mind that they are the first point of contact on the vessel for anyone boarding.If a vessel is alongside a berth affected by\ntidal conditions, constant reassessment of the situation should be carried out. In addition, the watchman must have access to the\ntimes of high and low waters and be aware of any cargo operations which may affect the vessel’s trim. If a watchman is not present\nat the gangway and an incident occurs, the vessel’s crew may carry on with their duties unaware of the situation.\n(Gangways, 2014)\nThe deck watch has a responsibility to make all visitors aware of any specific hazards of the cargo or operations onboard the vessel\nand point out instructions to visitors what to do in the event of an emergency.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.2","internal_question_no":"12A.002","question_sort_key":12100200.448,"question_text":"Has a Ship Security Officer (SSO) been appointed and trained adequately to perform the duties of SSO and have all crew received security-related training and instructions?","guide_to_inspection":"The duties and responsibilities of the SSO shall include, but are not limited to:\n> Undertaking regular security inspections of the ship to ensure that appropriate security measures are maintained\n> Maintaining and supervising the implementation of the SSP, including any amendments to the plan\n> Coordinating the security aspects of the handling of cargo and ship’s stores with other shipboard personnel and with the\nrelevant PFSOs\n> Proposing modifications to the SSP\n> Reporting to the company’s security officer (CSO) any deficiencies and non-conformities identified during internal audits,\nperiodic reviews, security inspections and verifications of compliance and implementing any corrective actions\n> Enhancing security awareness and vigilance on board\n> Ensuring that adequate training has been provided to shipboard personnel, as appropriate\n> Reporting all security incidents\n> Coordinating implementation of the SSP with the CSO and the relevant Port Facility Security Officer (PFSO)\n> Ensuring that security equipment is properly operated, tested, and calibrated, and ensuring the occurrence of ship security\ndrills and exercises.\n> Ensuring the proper maintenance of all records pertaining to the ship’s security\n> Notifying the CSO of ship security incidents and any breaches of this regulation. In the absence of a CSO, notify law\nenforcement agencies and other law enforcement respondents of ship security incidents and any breaches of this\nregulation, and\n> Ensuring that all security measures set forth in this regulation are implemented and enforced.\n(ISPS Code, 2003)\nIn accordance to the revised STCW 2010 Code as of 1st January 2014 all seafarers must receive approved security awareness\ntraining. (STCW cod e Reg A-VI/6-1)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":193,"source_page_end":193,"raw_source_text":"Has a Ship Security Officer (SSO) been appointed and trained adequately to perform the duties\nof SSO and have all crew received security-related training and instructions? (V)\nGuide to Inspection\nThe duties and responsibilities of the SSO shall include, but are not limited to:\n> Undertaking regular security inspections of the ship to ensure that appropriate security measures are maintained\n> Maintaining and supervising the implementation of the SSP, including any amendments to the plan\n> Coordinating the security aspects of the handling of cargo and ship’s stores with other shipboard personnel and with the\nrelevant PFSOs\n> Proposing modifications to the SSP\n> Reporting to the company’s security officer (CSO) any deficiencies and non-conformities identified during internal audits,\nperiodic reviews, security inspections and verifications of compliance and implementing any corrective actions\n> Enhancing security awareness and vigilance on board\n> Ensuring that adequate training has been provided to shipboard personnel, as appropriate\n> Reporting all security incidents\n> Coordinating implementation of the SSP with the CSO and the relevant Port Facility Security Officer (PFSO)\n> Ensuring that security equipment is properly operated, tested, and calibrated, and ensuring the occurrence of ship security\ndrills and exercises.\n> Ensuring the proper maintenance of all records pertaining to the ship’s security\n> Notifying the CSO of ship security incidents and any breaches of this regulation. In the absence of a CSO, notify law\nenforcement agencies and other law enforcement respondents of ship security incidents and any breaches of this\nregulation, and\n> Ensuring that all security measures set forth in this regulation are implemented and enforced.\n(ISPS Code, 2003)\nIn accordance to the revised STCW 2010 Code as of 1st January 2014 all seafarers must receive approved security awareness\ntraining. (STCW cod e Reg A-VI/6-1)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.3","internal_question_no":"12A.003","question_sort_key":12100300.449,"question_text":"Are deck officers familiar with the function and use of the Ship Security Alert System and is the Ship Security Alert System being tested regularly?","guide_to_inspection":"The inspector shall not ask for the details and location of the ship’s Security Alert System.\nAll ships constructed after 1st July 2004 shall be fitted with a ship security alert system.\nThe ship security alert system shall, when activated, initiate, and transmit a ship-to-shore security alert to a competent authority,\nwhich in these circumstances may include the Company, identifying the ship, its location and indicating that the security of the\nship is under threat or it has been compromised.\nIt shall not send the security alert to other ships or raise the alarm on board, and it shall continue until deactivated or reset.\nThe ship security alert system shall be capable of being activated from the navigation bridge, and in at least one other location.\n(SOLAS 74, 2014)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":193,"source_page_end":193,"raw_source_text":"Are deck officers familiar with the function and use of the Ship Security Alert System and is the\nShip Security Alert System being tested regularly? (V)\nGuide to Inspection\nThe inspector shall not ask for the details and location of the ship’s Security Alert System.\nAll ships constructed after 1st July 2004 shall be fitted with a ship security alert system.\nThe ship security alert system shall, when activated, initiate, and transmit a ship-to-shore security alert to a competent authority,\nwhich in these circumstances may include the Company, identifying the ship, its location and indicating that the security of the\nship is under threat or it has been compromised.\nIt shall not send the security alert to other ships or raise the alarm on board, and it shall continue until deactivated or reset.\nThe ship security alert system shall be capable of being activated from the navigation bridge, and in at least one other location.\n(SOLAS 74, 2014)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.4","internal_question_no":"12A.004","question_sort_key":12100400.45,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":194,"source_page_end":194,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.5","internal_question_no":"12A.005","question_sort_key":12100500.451,"question_text":"If the vessel has transited or is expected to transit a high-risk piracy area, have updated security charts and relevant publications been provided, and has a voyage risk assessment been completed?","guide_to_inspection":"ADMIRALTY Maritime Security Charts contain safety-critical information to assist bridge crews in the planning of safe passages\nthrough high-risk areas. All information has been gathered by the UKHO through work with NATO and other government\norganisations, ensuring each chart has the most accurate, up-to-date, and verified information available.\nEach Maritime Security Chart includes:\n> Information about dangers to the security of navigation including piracy, terrorism, embargoes, mine warfare, exclusion\nzones, blockades, and illegal fishing. This information, when used alongside official navigational charts, can help to ensure\nthe safety of ships, crew, and cargo.\n> General security advice, self-protective measures, security procedures and regional contacts, as well as routeing and\nreporting requirements implemented by military or security forces.\n> Weekly updates and new editions to help maintain high levels of accuracy and safety. Guides also include ADMIRALTY\nQuick Response (QR) codes for quick access to a list of all Notices to Mariners (NMs) that affect the specific chart or\n> publication.\n> Maritime Security Charts should be kept up to date with the latest security-critical navigational information. The Security\nRelated Information to Mariners (SRIM) service provides all the data needed to maintain your charts from official\ngovernment sources.\n(Admiralty.co.uk, 2018)\nThe company’s security officer (CSO) and the vessel’s Master have the combined responsibility to produce a voyage risk\nassessment. The procedure for this should be outlined in the vessels SMS. The risk assessment should include:\n> Highlighting areas of increased threat to the vessel. Identify the high-risk areas for that region\n> Identifying methods often used by pirates in these areas, and vulnerable areas where pirates could board\n> The ships own characteristics including handling, freeboard, speed, and general arrangement\n> Military or official organisation cooperation and reporting requirements\n> Existing guidelines and information sources\n> Ship and company procedures, communication, and chain of command.\nThe vessel’s manager should implement appropriate measures to meet the threat of piracy by adopting IMO and other industry-\nrecommended practices suitable for the circumstances of the voyage and ship type.\n(Maritime Security – General Recommendations, 2017)\nMaritime security threats vary across regions and within them, both in terms of the nature of the threats and their severity. For\nadditional information, reference should be made to the Introduction to Best Management Practices Maritime Security, the BMP\nMarine security publication. Please click here to access the publication.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":194,"source_page_end":194,"raw_source_text":"If the vessel has transited or is expected to transit a high-risk piracy area, have updated security charts\nand relevant publications been provided, and has a voyage risk assessment been completed? (V)\nGuide to Inspection\nADMIRALTY Maritime Security Charts contain safety-critical information to assist bridge crews in the planning of safe passages\nthrough high-risk areas. All information has been gathered by the UKHO through work with NATO and other government\norganisations, ensuring each chart has the most accurate, up-to-date, and verified information available.\nEach Maritime Security Chart includes:\n> Information about dangers to the security of navigation including piracy, terrorism, embargoes, mine warfare, exclusion\nzones, blockades, and illegal fishing. This information, when used alongside official navigational charts, can help to ensure\nthe safety of ships, crew, and cargo.\n> General security advice, self-protective measures, security procedures and regional contacts, as well as routeing and\nreporting requirements implemented by military or security forces.\n> Weekly updates and new editions to help maintain high levels of accuracy and safety. Guides also include ADMIRALTY\nQuick Response (QR) codes for quick access to a list of all Notices to Mariners (NMs) that affect the specific chart or\n> publication.\n> Maritime Security Charts should be kept up to date with the latest security-critical navigational information. The Security\nRelated Information to Mariners (SRIM) service provides all the data needed to maintain your charts from official\ngovernment sources.\n(Admiralty.co.uk, 2018)\nThe company’s security officer (CSO) and the vessel’s Master have the combined responsibility to produce a voyage risk\nassessment. The procedure for this should be outlined in the vessels SMS. The risk assessment should include:\n> Highlighting areas of increased threat to the vessel. Identify the high-risk areas for that region\n> Identifying methods often used by pirates in these areas, and vulnerable areas where pirates could board\n> The ships own characteristics including handling, freeboard, speed, and general arrangement\n> Military or official organisation cooperation and reporting requirements\n> Existing guidelines and information sources\n> Ship and company procedures, communication, and chain of command.\nThe vessel’s manager should implement appropriate measures to meet the threat of piracy by adopting IMO and other industry-\nrecommended practices suitable for the circumstances of the voyage and ship type.\n(Maritime Security – General Recommendations, 2017)\nMaritime security threats vary across regions and within them, both in terms of the nature of the threats and their severity. For\nadditional information, reference should be made to the Introduction to Best Management Practices Maritime Security, the BMP\nMarine security publication. Please click here to access the publication.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.6","internal_question_no":"12A.006","question_sort_key":12100600.452,"question_text":"Have preventive measures been taken by the Master and crew during the stay in port and prior to departure to prevent stowaways?","guide_to_inspection":"The issue of stowaways is one which has existed ever since vessels began to trade. Procedures for the prevention of stowaways\nshould be incorporated in the Safety Management System and should be effectively implemented by the Master and the crew\non board the ship.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":194,"source_page_end":194,"raw_source_text":"Have preventive measures been taken by the Master and crew during the stay in port and prior\nto departure to prevent stowaways? (V)\nGuide to Inspection\nThe issue of stowaways is one which has existed ever since vessels began to trade. Procedures for the prevention of stowaways\nshould be incorporated in the Safety Management System and should be effectively implemented by the Master and the crew\non board the ship.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.7","internal_question_no":"12A.007","question_sort_key":12100700.453,"question_text":"Are cyber security policies and procedures integrated into the safety management system, and has the cyber security management system been evaluated and certified?","guide_to_inspection":"Record Finding if cyber security management has not been incorporated into the vessel’s SMS by the company’s first annual\nverification of the DOC after January 1, 2021.\nThe cyber security management shall:\n> Identify the roles and responsibilities of users, key personnel, and management both ashore and on board\n> Identify the systems, assets, data and capabilities, which if disrupted, could pose risks to the ship’s operations and safety\n> Implement technical measures to protect against a cyber-incident and ensure continuity of operations. This may include\nconfiguration of networks, access control to networks and systems, communication and boundary defence and the use of\nprotection and detection software\n> Implement activities and plans (procedural protection measures) to provide resilience against cyber incidents. This may\ninclude training and awareness, software maintenance, remote and local access, access privileges, use of removable\nmedia and equipment disposal\n> Implement activities to prepare for and respond to cyber incidents.\n(The Guidelines on Cyber Security On board Ships, 2017)\nThe IMO have urged the maritime industry to refer to the requirements of Member Governments and Flag Administrations, as\nwell as applicable international and industry standards and best practices, for detailed guidelines on cyber risk management.\nAdditional guidance and standards may include, but are not limited to:\n1. The Guidelines on Cyber Security Onboard Ships produced and supported by ICS, IUMI, BIMCO, OCIMF, INTERTANKO,\nINTERCARGO, InterManager, WSC and SYBAss.\n2. Consolidated IACS Recommendation on cyber resilience (Rec 166).\n3. ISO/IEC 27001 standard on Information technology – Security techniques –Information security management systems –\nRequirements. Published jointly by the International Organization for Standardization (ISO) and the International\nElectrotechnical Commission (IEC).\n4. United States National Institute of Standards and Technology’s Framework for Improving Critical Infrastructure Cybersecurity\n(the NIST Framework).\nReference should be made to the most current version of any guidance or standards utilized.\n(The additional guidance and standards are listed as a non-exhaustive reference to further detailed information for users of\nthese Guidelines. The referenced guidance and standards have not been issued by the Organization and their use remains at the\ndiscretion of individual users of these Guidelines.)\n(IMO Guidelines on Maritime Cyber Risk Management 2021)\nAs computer technology advances, the nature of digital attacks will continue to evolve. To secure the safety of the digital\ninfrastructure, shipping companies are strongly encouraged to go above and beyond regulatory compliance and implement a\nmore proactive cyber-risk management approach.\nRightShip urges vessel managers to create a robust cyber security management system to avoid and reduce cyber threats\nto their ships by engaging cyber security expert firms. The system should undergo an operational, technical, and physical\nevaluation in accordance with industry standards, and be certified by an expert cyber security firm. Example of cyber security\nexpert firms include classification societies and other firms specializing in this domain.\nThe term “Cyber Security Expert Firm” denotes a professional entity with proven proficiency in certifying management systems\nunder the ISM Code and/or cyber security management systems in accordance with ISO/IEC 27001 standards. These firms\npossess the requisite skills, technological acumen, and training to safeguard an enterprise’s sensitive data from both internal\nand external threats.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":195,"source_page_end":195,"raw_source_text":"Are cyber security policies and procedures integrated into the safety management system, and has\nthe cyber security management system been evaluated and certified? (V)\nGuide to Inspection\nRecord Finding if cyber security management has not been incorporated into the vessel’s SMS by the company’s first annual\nverification of the DOC after January 1, 2021.\nThe cyber security management shall:\n> Identify the roles and responsibilities of users, key personnel, and management both ashore and on board\n> Identify the systems, assets, data and capabilities, which if disrupted, could pose risks to the ship’s operations and safety\n> Implement technical measures to protect against a cyber-incident and ensure continuity of operations. This may include\nconfiguration of networks, access control to networks and systems, communication and boundary defence and the use of\nprotection and detection software\n> Implement activities and plans (procedural protection measures) to provide resilience against cyber incidents. This may\ninclude training and awareness, software maintenance, remote and local access, access privileges, use of removable\nmedia and equipment disposal\n> Implement activities to prepare for and respond to cyber incidents.\n(The Guidelines on Cyber Security On board Ships, 2017)\nThe IMO have urged the maritime industry to refer to the requirements of Member Governments and Flag Administrations, as\nwell as applicable international and industry standards and best practices, for detailed guidelines on cyber risk management.\nAdditional guidance and standards may include, but are not limited to:\n1. The Guidelines on Cyber Security Onboard Ships produced and supported by ICS, IUMI, BIMCO, OCIMF, INTERTANKO,\nINTERCARGO, InterManager, WSC and SYBAss.\n2. Consolidated IACS Recommendation on cyber resilience (Rec 166).\n3. ISO/IEC 27001 standard on Information technology – Security techniques –Information security management systems –\nRequirements. Published jointly by the International Organization for Standardization (ISO) and the International\nElectrotechnical Commission (IEC).\n4. United States National Institute of Standards and Technology’s Framework for Improving Critical Infrastructure Cybersecurity\n(the NIST Framework).\nReference should be made to the most current version of any guidance or standards utilized.\n(The additional guidance and standards are listed as a non-exhaustive reference to further detailed information for users of\nthese Guidelines. The referenced guidance and standards have not been issued by the Organization and their use remains at the\ndiscretion of individual users of these Guidelines.)\n(IMO Guidelines on Maritime Cyber Risk Management 2021)\nAs computer technology advances, the nature of digital attacks will continue to evolve. To secure the safety of the digital\ninfrastructure, shipping companies are strongly encouraged to go above and beyond regulatory compliance and implement a\nmore proactive cyber-risk management approach.\nRightShip urges vessel managers to create a robust cyber security management system to avoid and reduce cyber threats\nto their ships by engaging cyber security expert firms. The system should undergo an operational, technical, and physical\nevaluation in accordance with industry standards, and be certified by an expert cyber security firm. Example of cyber security\nexpert firms include classification societies and other firms specializing in this domain.\nThe term “Cyber Security Expert Firm” denotes a professional entity with proven proficiency in certifying management systems\nunder the ISM Code and/or cyber security management systems in accordance with ISO/IEC 27001 standards. These firms\npossess the requisite skills, technological acumen, and training to safeguard an enterprise’s sensitive data from both internal\nand external threats.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"12A","section_number":12,"section_letter":"A","section_title":"Security","printed_question_no":"12.8","internal_question_no":"12A.008","question_sort_key":12100800.454,"question_text":"Are measures in place for controlling the use of removable media such as USB memory sticks, CDs, DVDs, and diskettes on shipboard computers?","guide_to_inspection":"Removable media is a collective term for all methods of storing and transferring data between computers. This includes laptops, USB\nmemory sticks, CDs, DVDs, and diskettes.\nTransferring data from uncontrolled systems to controlled systems represents a major risk of introducing malware. Removable media can\nbe used to bypass layers of defences and can be used to attack systems that are otherwise not connected to the internet.\nA clear policy for the use of such media devices is essential; it must ensure that media devices are not normally used to transfer\ninformation between un-controlled and controlled systems.\nTo avoid unauthorised access, removable media blockers should be used on all physically accessible computers and network ports. (The\nGuidelines on Cyber Security on board Ships, 2017)\nECDIS should be protected from malware and virus attack. Access to USB and RJ-45 ports shall be controlled – i.e., disable or lock the\nports.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":195,"source_page_end":195,"raw_source_text":"Are measures in place for controlling the use of removable media such as USB memory sticks,\nCDs, DVDs, and diskettes on shipboard computers? (V)\nGuide to Inspection\nRemovable media is a collective term for all methods of storing and transferring data between computers. This includes laptops, USB\nmemory sticks, CDs, DVDs, and diskettes.\nTransferring data from uncontrolled systems to controlled systems represents a major risk of introducing malware. Removable media can\nbe used to bypass layers of defences and can be used to attack systems that are otherwise not connected to the internet.\nA clear policy for the use of such media devices is essential; it must ensure that media devices are not normally used to transfer\ninformation between un-controlled and controlled systems.\nTo avoid unauthorised access, removable media blockers should be used on all physically accessible computers and network ports. (The\nGuidelines on Cyber Security on board Ships, 2017)\nECDIS should be protected from malware and virus attack. Access to USB and RJ-45 ports shall be controlled – i.e., disable or lock the\nports.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.1","internal_question_no":"13A.001","question_sort_key":13100100.455,"question_text":"Are adequate engineering procedures, instructions and guidelines included in the SMS?","guide_to_inspection":"Engine room procedures shall provide specific guidance on how to operate and maintain engine rooms and all associated\nequipment, in a safe and responsible manner.\nAt a minimum, the SMS and safety management manual should include the following:\n> A system for allocating engineering watch keeping duties and responsibilities for operational procedures;\n> Guidelines for ensuring that crew members are trained and competent to undertake their duties on board;\n> Procedures for engine room operations including checklists\n> Procedures for critical operations, including bunkering, port arrival and departure;\n> Procedures for preventing and controlling pollution, including activities such as oil spill response and disposal of waste;\n> Emergency response procedures and instructions\n> A defect reporting procedure and system for rectifying defects;\n> Procedures for change management\n> Procedures for control, validity and changes for documentation\n> Reporting procedures for accident and near misses\n> Maintenance procedures, including control of work and permit to work systems;\n> Identification of critical machinery/equipment and procedures to ensure availability and for isolation/maintenance of\ncritical equipment;\n> Procedure for management of minimum critical and essential spares\n> A Planned Maintenance System and a method for recording maintenance activities\n> Procedures for crew familiarization and handover\n> A recognized system for identifying training needs.\n(Engine Room Procedures Guide 2024)\nOverridable engine power limitation (EPL) or overridable shaft power limitation (SHaPoLi) are commonly used to improve a\nship’s attained Energy Efficiency Existing Ship Index (EEXI) performance.\nThe company should provide guidelines for the appropriate use of overridable power limitation.\nOverridable Shaft Power Limitation (SHaPoLi) system means a verified and approved system for the limitation of the maximum\nshaft power by technical means that can only be overridden by the ship’s master or the officer in charge of navigational watch\n(OICNW) for the purpose of securing the safety of a ship or saving life at sea.\nOverridable Engine Power Limitation (EPL) system means a verified and approved system for the limitation of the maximum\nengine power by technical means that can only be overridden by the ship’s master or OICNW for the purpose of securing the\nsafety of a ship or saving life at sea.\n2.2.1 The SHaPoLi / EPL system should be non-permanent but should require the deliberate action of the ship’s master or\nOICNW to enable the use of unlimited shaft / engine power (power reserve) of the ship. For systems that use a Password/PIN\nto control access to the power reserve override, attention should be paid to ensure that the necessary Password/PIN is always\navailable when override is required.\n2.2.2 For SHaPoLi / EPL system for the electronically controlled engine, the control unit should inform the ship’s master or\nOICNW clearly and conspicuously when the ship’s shaft / engine power exceeds the limited shaft / engine power as stated in the\nOnboard Management Manual (OMM) for SHaPoLi / EPL or in any case of system malfunction.\n2.2.3 For EPL for the mechanically controlled engine, the sealing device should either:\n> visibly indicate removal of the sealing when the ship’s engine power exceeds the limited engine power as stated in the\nOMM for EPL or in any case of system malfunction; or\n> be equipped with other systems such as an alert-monitoring system which can indicate when the ship’s engine power\nexceeds the limited engine power as stated in the OMM for EPL or in any case of system malfunction and recording the\nuse of unlimited mode, verified by the Administration or the RO\n3.2 Any use of a power reserve should be recorded in the record page of the OMM for SHaPoLi / EPL, signed by the master and\nshould be kept on board. The record should include:\n> ship type;\n> IMO number;\n> ship size in DWT and/or GT, as applicable;\n> ship’s limited shaft / engine power and ship’s maximum unlimited shaft / engine power;\n> position of the ship and timestamp when the power reserve was used;\n> reason for using the power reserve;\n> Beaufort number and wave height or ice condition in case of using the power reserve under adverse weather condition;\n> supporting evidence (e.g. expected weather condition) in case of using the power reserve for avoidance action;\n> records from the SHaPoLi / EPL system for the electronically controlled engine during the power reserve was used; and\n> position of the ship and timestamp when the power limit was reactivated or replaced.\n3.3 Where an EPL/ShaPoLi override is activated but the power reserve is not subsequently used, this event should be recorded in\nthe bridge and engine-room logbooks.The engine-room logbook should record power used during the period when the override\nwas activated. The EPL/ShaPoLi should be reset as soon as possible, and details of the reset should also be recorded in the\nbridge and engine-room logbooks.\n3.4 In case of having used a power reserve, the ship should without delay notify its Administration or RO responsible for\nissuing the relevant certificate and the competent authority of the relevant port of destination with the information recorded in\naccordance with paragraph 3.2.\nOnboard Management Manual (OMM) for SHaPoLi / EPL\n4.1 The SHaPoLi / EPL system should be accompanied by the OMM for SHaPoLi / EPL that should be permanently on board the\nship for inspection.\n4.2 The OMM for SHaPoLi / EPL should be verified by the Administration or the RO after a survey verifying the ship’s attained\nEEXI, as required by regulation 5.4 of MARPOL Annex VI.\n( MEPC.335(76) 2021)\nThe Resolution MEPC.335(76) provides further guidelines on the shaft/engine power limitation system to comply with the EEXI\nrequirements and use of a power reserve. Please download the document here.\nIt is recommended that OPL override trainings are conducted every 3 months. If there has been a crew change of key members\nsuch as navigation or engine room officers, the training should be carried out immediately after sailing.\nSuch a training should include:\n> An explanation of the purpose, effects and limitation of the OPL.\n> Examples of circumstances when the OPL may need to be overridden.\n> An on-site demonstration to the extent possible so that the relevant officer can sight the location of the OPL and become\nfamiliar with its parts and tools required to override it.\n> Awareness of the time required to override the power limitation considering the type and location of the OPL.\n> Officers should be able to demonstrate that they are able to reset the limitation to the original conditions.\n>\nThe senior maintenance engineer should hold toolbox talks with the maintenance team at the start of each day and before\nstarting any major work. A toolbox talk is a short meeting to review the work, identify the risks, and discuss how those risks will\nbe managed.\nMaintenance and day work ratings should maintain a high standard of safety while carrying out their assigned duties. During\ntoolbox talks, the officer in charge of maintenance should encourage the crew to raise any doubts about the procedures, PPE\nand safety measures.\n(Engine room Procedures Guide 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":196,"source_page_end":197,"raw_source_text":"Are adequate engineering procedures, instructions and guidelines included in the SMS? (V)\nGuide to Inspection\nEngine room procedures shall provide specific guidance on how to operate and maintain engine rooms and all associated\nequipment, in a safe and responsible manner.\nAt a minimum, the SMS and safety management manual should include the following:\n> A system for allocating engineering watch keeping duties and responsibilities for operational procedures;\n> Guidelines for ensuring that crew members are trained and competent to undertake their duties on board;\n> Procedures for engine room operations including checklists\n> Procedures for critical operations, including bunkering, port arrival and departure;\n> Procedures for preventing and controlling pollution, including activities such as oil spill response and disposal of waste;\n> Emergency response procedures and instructions\n> A defect reporting procedure and system for rectifying defects;\n> Procedures for change management\n> Procedures for control, validity and changes for documentation\n> Reporting procedures for accident and near misses\n> Maintenance procedures, including control of work and permit to work systems;\n> Identification of critical machinery/equipment and procedures to ensure availability and for isolation/maintenance of\ncritical equipment;\n> Procedure for management of minimum critical and essential spares\n> A Planned Maintenance System and a method for recording maintenance activities\n> Procedures for crew familiarization and handover\n> A recognized system for identifying training needs.\n(Engine Room Procedures Guide 2024)\nOverridable engine power limitation (EPL) or overridable shaft power limitation (SHaPoLi) are commonly used to improve a\nship’s attained Energy Efficiency Existing Ship Index (EEXI) performance.\nThe company should provide guidelines for the appropriate use of overridable power limitation.\nOverridable Shaft Power Limitation (SHaPoLi) system means a verified and approved system for the limitation of the maximum\nshaft power by technical means that can only be overridden by the ship’s master or the officer in charge of navigational watch\n(OICNW) for the purpose of securing the safety of a ship or saving life at sea.\nOverridable Engine Power Limitation (EPL) system means a verified and approved system for the limitation of the maximum\nengine power by technical means that can only be overridden by the ship’s master or OICNW for the purpose of securing the\nsafety of a ship or saving life at sea.\n2.2.1 The SHaPoLi / EPL system should be non-permanent but should require the deliberate action of the ship’s master or\nOICNW to enable the use of unlimited shaft / engine power (power reserve) of the ship. For systems that use a Password/PIN\nto control access to the power reserve override, attention should be paid to ensure that the necessary Password/PIN is always\navailable when override is required.\n2.2.2 For SHaPoLi / EPL system for the electronically controlled engine, the control unit should inform the ship’s master or\nOICNW clearly and conspicuously when the ship’s shaft / engine power exceeds the limited shaft / engine power as stated in the\nOnboard Management Manual (OMM) for SHaPoLi / EPL or in any case of system malfunction.\n2.2.3 For EPL for the mechanically controlled engine, the sealing device should either:\n> visibly indicate removal of the sealing when the ship’s engine power exceeds the limited engine power as stated in the\nOMM for EPL or in any case of system malfunction; or\n> be equipped with other systems such as an alert-monitoring system which can indicate when the ship’s engine power\nexceeds the limited engine power as stated in the OMM for EPL or in any case of system malfunction and recording the\nuse of unlimited mode, verified by the Administration or the RO\n3.2 Any use of a power reserve should be recorded in the record page of the OMM for SHaPoLi / EPL, signed by the master and\nshould be kept on board. The record should include:\n> ship type;\n> IMO number;\n> ship size in DWT and/or GT, as applicable;\n> ship’s limited shaft / engine power and ship’s maximum unlimited shaft / engine power;\n> position of the ship and timestamp when the power reserve was used;\n> reason for using the power reserve;\n> Beaufort number and wave height or ice condition in case of using the power reserve under adverse weather condition;\n> supporting evidence (e.g. expected weather condition) in case of using the power reserve for avoidance action;\n> records from the SHaPoLi / EPL system for the electronically controlled engine during the power reserve was used; and\n> position of the ship and timestamp when the power limit was reactivated or replaced.\n3.3 Where an EPL/ShaPoLi override is activated but the power reserve is not subsequently used, this event should be recorded in\nthe bridge and engine-room logbooks.The engine-room logbook should record power used during the period when the override\nwas activated. The EPL/ShaPoLi should be reset as soon as possible, and details of the reset should also be recorded in the\nbridge and engine-room logbooks.\n3.4 In case of having used a power reserve, the ship should without delay notify its Administration or RO responsible for\nissuing the relevant certificate and the competent authority of the relevant port of destination with the information recorded in\naccordance with paragraph 3.2.\nOnboard Management Manual (OMM) for SHaPoLi / EPL\n4.1 The SHaPoLi / EPL system should be accompanied by the OMM for SHaPoLi / EPL that should be permanently on board the\nship for inspection.\n4.2 The OMM for SHaPoLi / EPL should be verified by the Administration or the RO after a survey verifying the ship’s attained\nEEXI, as required by regulation 5.4 of MARPOL Annex VI.\n( MEPC.335(76) 2021)\nThe Resolution MEPC.335(76) provides further guidelines on the shaft/engine power limitation system to comply with the EEXI\nrequirements and use of a power reserve. Please download the document here.\nIt is recommended that OPL override trainings are conducted every 3 months. If there has been a crew change of key members\nsuch as navigation or engine room officers, the training should be carried out immediately after sailing.\nSuch a training should include:\n> An explanation of the purpose, effects and limitation of the OPL.\n> Examples of circumstances when the OPL may need to be overridden.\n> An on-site demonstration to the extent possible so that the relevant officer can sight the location of the OPL and become\nfamiliar with its parts and tools required to override it.\n> Awareness of the time required to override the power limitation considering the type and location of the OPL.\n> Officers should be able to demonstrate that they are able to reset the limitation to the original conditions.\n>\nThe senior maintenance engineer should hold toolbox talks with the maintenance team at the start of each day and before\nstarting any major work. A toolbox talk is a short meeting to review the work, identify the risks, and discuss how those risks will\nbe managed.\nMaintenance and day work ratings should maintain a high standard of safety while carrying out their assigned duties. During\ntoolbox talks, the officer in charge of maintenance should encourage the crew to raise any doubts about the procedures, PPE\nand safety measures.\n(Engine room Procedures Guide 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.2","internal_question_no":"13A.002","question_sort_key":13100200.456,"question_text":"Are the responsibilities of watch standing engineers and engine ratings well-defined and clearly posted in the Engine Control Room? Is there a manning matrix for engineers that takes into account both planned and unplanned changes?","guide_to_inspection":"The Chief Engineer or designated representative should increase manning levels when required, whether planned or unplanned. As\nfar as possible, the work/rest hour requirements should still be met.\nPlanned Changes:\nThe Chief Engineer should identify planned changes in manning in consultation with the Master. The planned changes should be\nidentified for every passage of the ship. Examples of events/operations requiring planned manning changes are:\n> Arrival/departure;\n> Cargo operations\n> Bunkering\n> Fuel change overs;\n> Planned machinery overhauls; and\n> Docking for surveys and trial runs\n> Unplanned Changes:\n> In an emergency, the EOOW on duty should set a manning level appropriate to the situation. The EOOW should be encouraged\nto take these measures as early as necessary. Examples of events that may require an unplanned manning change include:\n> Navigation hazards;\n> Machinery faults\n> Adverse weather;\n> Electrical blackout;\n> Fire; and\n> Flooding.\n(Engine Room Procedures Guide 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":197,"source_page_end":197,"raw_source_text":"Are the responsibilities of watch standing engineers and engine ratings well-defined and clearly posted in\nthe Engine Control Room? Is there a manning matrix for engineers that takes into account both planned\nand unplanned changes? (V)\nGuide to Inspection\nThe Chief Engineer or designated representative should increase manning levels when required, whether planned or unplanned. As\nfar as possible, the work/rest hour requirements should still be met.\nPlanned Changes:\nThe Chief Engineer should identify planned changes in manning in consultation with the Master. The planned changes should be\nidentified for every passage of the ship. Examples of events/operations requiring planned manning changes are:\n> Arrival/departure;\n> Cargo operations\n> Bunkering\n> Fuel change overs;\n> Planned machinery overhauls; and\n> Docking for surveys and trial runs\n> Unplanned Changes:\n> In an emergency, the EOOW on duty should set a manning level appropriate to the situation. The EOOW should be encouraged\nto take these measures as early as necessary. Examples of events that may require an unplanned manning change include:\n> Navigation hazards;\n> Machinery faults\n> Adverse weather;\n> Electrical blackout;\n> Fire; and\n> Flooding.\n(Engine Room Procedures Guide 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.3","internal_question_no":"13A.003","question_sort_key":13100300.457,"question_text":"Has the Chief Engineer prepared specific standing orders, night and day orders, and have these orders been read, understood, and signed by the watch standing engineers, engine crew, and electrical engineer, where applicable?","guide_to_inspection":"The Chief Engineer should issue written standing orders for the engineering team. These should reflect the Chief Engineer’s own\nrequirements, and take into account the Master’s standing orders, the circumstances of the ship and trade, and the experience\nof the engineering team on board.\nStanding orders and instructions should not conflict with the SMS. However, they provide a good opportunity to give specific\nguidance about the occasions when the Chief Engineer should be consulted or called to the engine room.\nOn joining the ship, all relevant engineer officers should read, sign and date the standing orders. A reference copy of the order\nshould be readily available in the ECR.\nThe Chief Engineer should issue night orders and day orders in the engine department order book, to provide specific\ninstructions to address circumstances and requirements outside the normal routines. All EOOWs should fully understand and\nacknowledge these orders when going on or off watch.\n(Engine Room Procedures Guide 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":198,"source_page_end":198,"raw_source_text":"Has the Chief Engineer prepared specific standing orders, night and day orders, and have these orders been\nread, understood, and signed by the watch standing engineers, engine crew, and electrical engineer, where\napplicable? (V & M)\nGuide to Inspection\nThe Chief Engineer should issue written standing orders for the engineering team. These should reflect the Chief Engineer’s own\nrequirements, and take into account the Master’s standing orders, the circumstances of the ship and trade, and the experience\nof the engineering team on board.\nStanding orders and instructions should not conflict with the SMS. However, they provide a good opportunity to give specific\nguidance about the occasions when the Chief Engineer should be consulted or called to the engine room.\nOn joining the ship, all relevant engineer officers should read, sign and date the standing orders. A reference copy of the order\nshould be readily available in the ECR.\nThe Chief Engineer should issue night orders and day orders in the engine department order book, to provide specific\ninstructions to address circumstances and requirements outside the normal routines. All EOOWs should fully understand and\nacknowledge these orders when going on or off watch.\n(Engine Room Procedures Guide 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.4","internal_question_no":"13A.004","question_sort_key":13100400.458,"question_text":"If the vessel has been certified for periodically unattended machinery spaces operation (UMS), is the machinery space being operated in that mode?","guide_to_inspection":"Record a Finding if the machinery space is not being operated in UMS mode, as result of defective equipment/machinery or\nunreliability of the UMS system.\nThe finding should not be raised if the vessel’s machinery space is manned for operational reasons, such as transiting high-\nrisk piracy areas, hold cleaning, post dry-dock (for a period of up to one month), or manoeuvring, provided there are sufficient\nengineers and crew on board to safely man the machinery space.\nBefore changing over to unattended operation, the EOOW should complete a round of the machinery spaces, following a\nchecklist all the parameters to be tested and verified. A reference to checklist B2: Preparation for UMS of Engine Room\nProcedures Guide shall be made (Second Edition 2024)\n(Engine Room Procedures Guide , 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":198,"source_page_end":198,"raw_source_text":"If the vessel has been certified for periodically unattended machinery spaces operation (UMS), is the\nmachinery space being operated in that mode? (V)\nGuide to Inspection\nRecord a Finding if the machinery space is not being operated in UMS mode, as result of defective equipment/machinery or\nunreliability of the UMS system.\nThe finding should not be raised if the vessel’s machinery space is manned for operational reasons, such as transiting high-\nrisk piracy areas, hold cleaning, post dry-dock (for a period of up to one month), or manoeuvring, provided there are sufficient\nengineers and crew on board to safely man the machinery space.\nBefore changing over to unattended operation, the EOOW should complete a round of the machinery spaces, following a\nchecklist all the parameters to be tested and verified. A reference to checklist B2: Preparation for UMS of Engine Room\nProcedures Guide shall be made (Second Edition 2024)\n(Engine Room Procedures Guide , 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.5","internal_question_no":"13A.005","question_sort_key":13100500.459,"question_text":"If the engine room is not being operated in UMS mode, are there sufficient engineers and crew on board for safe operation of the machinery space?","guide_to_inspection":"In case the Engine Room (ER) is not suitable for unmanned operation, the composition of the crew should be adapted for\nmanned ER services.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":198,"source_page_end":198,"raw_source_text":"If the engine room is not being operated in UMS mode, are there sufficient engineers and crew\non board for safe operation of the machinery space? (V)\nGuide to Inspection\nIn case the Engine Room (ER) is not suitable for unmanned operation, the composition of the crew should be adapted for\nmanned ER services.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.6","internal_question_no":"13A.006","question_sort_key":13100600.46,"question_text":"Have the entry requirements to the engine room when operating in UMS mode been documented, posted at the entrance to the engine room and understood by all crew?","guide_to_inspection":"Seafarers should never enter or remain in an unmanned machinery space alone unless they have received permission from or\nbeen instructed by the engineer officer in charge at the time. They may only be sent to carry out a specific task that they may be\nexpected to complete in a comparatively short time.\nBefore entering the space, at regular intervals whilst in the space and upon leaving the space, they must report by telephone, or\nother means provided, to the duty deck officer. Before they enter the space, the method of reporting should be clearly explained.\nIf it is the engineer officer in charge who enters the machinery space alone, they too should report to the deck officer before\nentry, at regular intervals whilst in the space and upon leaving the space.\nNotice of safety precautions to be observed by seafarers working in unmanned machinery spaces should be clearly displayed\nat all entrances to the space. Warning should be given that in unmanned machinery spaces there is a likelihood of machinery\nsuddenly starting up.\nIf there is a personnel alarm system in place, reporting at regular intervals may be omitted. A personnel alarm is a system that\nwill indicate a person’s presence and their well-being in unmanned machinery spaces. Vessels without a personnel alarm\nsystem should have additional guidance recorded in the safety management system.\n(Code of Safe Working Practice s for Merchant Seafarer’s, 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":198,"source_page_end":198,"raw_source_text":"Have the entry requirements to the engine room when operating in UMS mode been documented,\nposted at the entrance to the engine room and understood by all crew? (V)\nGuide to Inspection\nSeafarers should never enter or remain in an unmanned machinery space alone unless they have received permission from or\nbeen instructed by the engineer officer in charge at the time. They may only be sent to carry out a specific task that they may be\nexpected to complete in a comparatively short time.\nBefore entering the space, at regular intervals whilst in the space and upon leaving the space, they must report by telephone, or\nother means provided, to the duty deck officer. Before they enter the space, the method of reporting should be clearly explained.\nIf it is the engineer officer in charge who enters the machinery space alone, they too should report to the deck officer before\nentry, at regular intervals whilst in the space and upon leaving the space.\nNotice of safety precautions to be observed by seafarers working in unmanned machinery spaces should be clearly displayed\nat all entrances to the space. Warning should be given that in unmanned machinery spaces there is a likelihood of machinery\nsuddenly starting up.\nIf there is a personnel alarm system in place, reporting at regular intervals may be omitted. A personnel alarm is a system that\nwill indicate a person’s presence and their well-being in unmanned machinery spaces. Vessels without a personnel alarm\nsystem should have additional guidance recorded in the safety management system.\n(Code of Safe Working Practice s for Merchant Seafarer’s, 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ121$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 12/15 imported.' AS result,
  '10A.003' AS chunk_first_question,
  '13A.006' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
